#define RADIX 255
#define INTOFF 9
#define LITSIZE 4

static long range = 1, fraction = 0;
static int cc[2000000];

static void emit_digit(int d){ putchar((unsigned char)((d+1)&0xFF)); }
static void normalize(void){ while(range<RADIX){ long d=fraction/RADIX; fraction=(fraction-d*RADIX)*RADIX; range*=RADIX; emit_digit((int)d); } }
static void put_bit(int ctx,int bit){ normalize(); int idx=ctx*2; int c0=cc[idx], c1=cc[idx+1]; long split=range*(c0+1)/(c0+c1+2); if(bit==0) range=split; else { fraction+=split; range-=split; } cc[idx+bit]++; }
static void encode_integer(int start,int ctx,int value){
    long result = (long)value + (1L << start);
    int tmp = 0;
    while ((1L << (tmp + 1)) <= result) tmp++;
    int ctx2 = ctx * 99;
    for (int t = start + 1; t <= tmp; t++) put_bit(t + ctx2, 0);
    put_bit(tmp + 1 + ctx2, 1);
    for (int i = tmp - 1; i >= 0; i--) put_bit(ctx, (int)((result >> i) & 1));
}
static void finish(void){ normalize(); for(int i=0;i<8;i++) emit_digit(0); }
int main(int argc,char**argv){
